SELECT SUM(duration) AS total_visit_duration
FROM browsing_history
WHERE user_id = 1;

SELECT SUM(engagement_duration) AS total_engagement_duration
FROM site_engagement
WHERE user_id = 0;

SELECT title
FROM browsing_history
ORDER BY visit_count DESC;

SELECT visit_count
FROM browsing_history
WHERE user_id = 1;

SELECT url, AVG(duration) AS average_visit_duration
FROM browsing_history
GROUP BY url;

SELECT AVG(engagement_duration) AS average_engagement_duration
FROM site_engagement
WHERE user_id = 0;

SELECT engagement_score
FROM site_engagement
WHERE engagement_score > 80;

SELECT MAX(visit_count) AS max_visit_count
FROM browsing_history
WHERE visit_count > 5;
